const l=["pretty","large","big","small","tall","short","long","handsome","plain","quaint","clean","elegant","easy","angry","cheap","nice","better","best","modern"],o=["red","yellow","blue","green","pink","brown","purple","brown","white","black","orange"],s=["table","chair","house","bbq","desk","car","pony","cookie","sandwich","burger","pizza","mouse","keyboard"];let i=1;function h(){i=1}function b(){return`${l[Math.random()*l.length|0]} ${o[Math.random()*o.length|0]} ${s[Math.random()*s.length|0]}`}function g(n){const r=new Array(n);for(let e=0;e<n;e++)r[e]={id:i++,label:b()};return r}function u(n,r=100){if(!Array.isArray(n)||n.length<r*2)return n;const e=n.slice();for(let t=0;t<r;t++){const a=e.length-1-t,c=e[t];e[t]=e[a],e[a]=c}return e}export{g as b,h as r,u as s};
